func TestAuthSetTokenDoesNotPersistEnvBearerAuth(t *testing.T) {
	configPath := filepath.Join(t.TempDir(), "config.toml")
	t.Setenv("AIRFLOW_ADMIN_BEARER_AUTH", "old-token")

	flags := &rootFlags{configPath: configPath, asJSON: true}
	cmd := newAuthSetTokenCmd(flags)
	var out bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetArgs([]string{"new-token"})

	if err := cmd.Execute(); err != nil {
		t.Fatalf("set-token: %v", err)
	}

	raw, err := os.ReadFile(configPath)
	if err != nil {
		t.Fatalf("read config: %v", err)
	}
	if strings.Contains(string(raw), "old-token") {
		t.Fatalf("config persisted env bearer token: %s", raw)
	}
	if !strings.Contains(string(raw), "new-token") {
		t.Fatalf("config did not persist new token: %s", raw)
	}

	t.Setenv("AIRFLOW_ADMIN_BEARER_AUTH", "")
	cfg, err := config.Load(configPath)
	if err != nil {
		t.Fatalf("reload config: %v", err)
	}
	if got := cfg.AuthHeader(); got != "Bearer new-token" {
		t.Fatalf("AuthHeader() = %q, want Bearer new-token", got)
	}
}
